4	import { hasMatchesForSwap, findMatches } from "./match-detector.js";
5	
6	/**
7	 * Main entry point: finds the best swap on the board
8	 * @param {Match3Game} game - The game instance
9	 * @returns {{row1: number, col1: number, row2: number, col2: number, score: number} | null}
10	 */
11	export function findBestSwap(game) {
12	    const validSwaps = findAllValidSwaps(game);
13	
14	    if (validSwaps.length === 0) {
15	        return null;
16	    }
17	
18	    const evaluatedSwaps = [];
19	
20	    // Save original board reference and flags (don't copy - keep the original intact)
21	    const originalBoard = game.board;
22	    const originalIsUserSwap = game.isUserSwap;
23	    const originalLastSwapPosition = game.lastSwapPosition;
24	
25	    // Create a working copy for hint evaluation
26	    // This copy is what we'll modify during evaluation
27	    const createWorkingCopy = () => originalBoard.map((row) => row.map((tile) => (tile ? { ...tile } : null)));
28	
29	    for (const swap of validSwaps) {
30	        // Set up a fresh working copy for each evaluation
31	        game.board = createWorkingCopy();
32	
33	        const result = evaluateSwap(game, swap.row1, swap.col1, swap.row2, swap.col2);
34	
35	        if (result !== null) {
36	            evaluatedSwaps.push(result);
37	        }
38	    }
39	
40	    // Restore original board reference (not a copy - the actual original)
41	    game.board = originalBoard;
42	    game.isUserSwap = originalIsUserSwap;
43	    game.lastSwapPosition = originalLastSwapPosition;
44	
45	    if (evaluatedSwaps.length === 0) {
46	        return null;
47	    }
48	
49	    // Sort by score descending, with tiebreaker for top-left position
50	    evaluatedSwaps.sort((a, b) => {
51	        if (b.score !== a.score) {
52	            return b.score - a.score;
53	        }
54	        // Tiebreaker: prefer top-left positions
55	        const posA = a.row1 + a.col1;
56	        const posB = b.row1 + b.col1;
57	        return posA - posB;
58	    });
59	
60	    return evaluatedSwaps[0];
61	}
62	
63	/**
64	 * Find all valid adjacent swap pairs on the board
65	 * @param {Match3Game} game - The game instance
66	 * @returns {Array<{row1: number, col1: number, row2: number, col2: number}>}
67	 */
68	export function findAllValidSwaps(game) {
69	    const validSwaps = [];
70	
71	    for (let row = 0; row < game.boardHeight; row++) {
72	        for (let col = 0; col < game.boardWidth; col++) {
73	            // Check right neighbor
74	            if (col < game.boardWidth - 1) {
75	                if (isValidSwapPair(game, row, col, row, col + 1)) {
76	                    validSwaps.push({
77	                        row1: row,
78	                        col1: col,
79	                        row2: row,
80	                        col2: col + 1,
81	                    });
82	                }
83	            }
84	
85	            // Check down neighbor
86	            if (row < game.boardHeight - 1) {
87	                if (isValidSwapPair(game, row, col, row + 1, col)) {
88	                    validSwaps.push({
89	                        row1: row,
90	                        col1: col,
91	                        row2: row + 1,
92	                        col2: col,
93	                    });
94	                }
95	            }
96	        }
97	    }
98	
99	    return validSwaps;
100	}
101	
102	/**
103	 * Check if two positions can be swapped
104	 * @param {Match3Game} game - The game instance
105	 * @param {number} row1 - First tile row
106	 * @param {number} col1 - First tile column
107	 * @param {number} row2 - Second tile row
108	 * @param {number} col2 - Second tile column
109	 * @returns {boolean}
110	 */
111	function isValidSwapPair(game, row1, col1, row2, col2) {
112	    const tile1 = game.board[row1]?.[col1];
113	    const tile2 = game.board[row2]?.[col2];
114	
115	    // Check if tiles exist
116	    if (!tile1 || !tile2) {
117	        return false;
118	    }
119	
120	    // Check if either tile is blocked
121	    if (isBlocked(tile1) || isBlockedWithLife(tile1)) {
122	        return false;
123	    }
124	
125	    if (isBlocked(tile2) || isBlockedWithLife(tile2)) {
126	        return false;
127	    }
128	
129	    return true;
130	}
131	
132	/**
133	 * Evaluate a swap and compute its score
134	 * @param {Match3Game} game - The game instance
135	 * @param {number} row1 - First tile row
136	 * @param {number} col1 - First tile column
137	 * @param {number} row2 - Second tile row
138	 * @param {number} col2 - Second tile column
139	 * @returns {{row1: number, col1: number, row2: number, col2: number, score: number, matches: Array} | null}
140	 */
141	function evaluateSwap(game, row1, col1, row2, col2) {
142	    // Temporarily swap tiles
143	    const temp = game.board[row1][col1];
144	    game.board[row1][col1] = game.board[row2][col2];
145	    game.board[row2][col2] = temp;
146	
147	    // Set flag for joker activation
148	    game.isUserSwap = true;
149	    game.lastSwapPosition = {
150	        row: row2,
151	        col: col2,
152	        movedFrom: { row: row1, col: col1 },
153	    };
154	
155	    // Check if this swap creates matches
156	    const hasMatches = hasMatchesForSwap(game, row1, col1, row2, col2);
157	
158	    if (!hasMatches) {
159	        // Swap back
160	        game.board[row2][col2] = game.board[row1][col1];
161	        game.board[row1][col1] = temp;
162	        return null;
163	    }
164	
165	    // Get detailed match information
166	    const matches = findMatches(game);
167	
168	    // Swap back
169	    game.board[row2][col2] = game.board[row1][col1];
170	    game.board[row1][col1] = temp;
171	
172	    // Calculate score
173	    const score = calculateSwapScore(game, matches);
174	
175	    // Determine swap direction for nudge animation
176	    let direction1, direction2;
177	    if (col2 > col1) {
178	        direction1 = "right";
179	        direction2 = "left";
180	    } else if (col2 < col1) {
181	        direction1 = "left";
182	        direction2 = "right";
183	    } else if (row2 > row1) {
184	        direction1 = "down";
185	        direction2 = "up";
186	    } else {
187	        direction1 = "up";
188	        direction2 = "down";
189	    }
190	
191	    // Separate matches by which swap tile they involve
192	    const matchesForTile1 = matches.filter((match) =>
193	        match.tiles.some((tile) => tile.row === row1 && tile.col === col1),
194	    );
195	    const matchesForTile2 = matches.filter((match) =>
196	        match.tiles.some((tile) => tile.row === row2 && tile.col === col2),
197	    );
198	
199	    // Calculate score for each group to find the best one
200	    const score1 = matchesForTile1.length > 0 ? calculateSwapScore(game, matchesForTile1) : 0;
201	    const score2 = matchesForTile2.length > 0 ? calculateSwapScore(game, matchesForTile2) : 0;
202	
203	    // Use matches from the higher-scoring tile only
204	    const bestMatches = score1 >= score2 ? matchesForTile1 : matchesForTile2;
205	
206	    // Collect tiles from the best matches only
207	    // Translate post-swap positions back to pre-swap positions for display
208	    const matchTiles = [];
209	    for (const match of bestMatches) {
210	        for (const tile of match.tiles) {
211	            let displayRow = tile.row;
212	            let displayCol = tile.col;
213	
214	            // If this tile is at a swap position, translate it back
215	            if (tile.row === row1 && tile.col === col1) {
216	                // This tile is at position 1 after swap, so it was at position 2 before
217	                displayRow = row2;
218	                displayCol = col2;
219	            } else if (tile.row === row2 && tile.col === col2) {
220	                // This tile is at position 2 after swap, so it was at position 1 before
221	                displayRow = row1;
222	                displayCol = col1;
223	            }
224	
225	            matchTiles.push({ row: displayRow, col: displayCol });
226	        }
227	    }
228	
229	    return {
230	        row1,
231	        col1,
232	        row2,
233	        col2,
234	        direction1,
235	        direction2,
236	        score,
237	        matches,
238	        matchTiles,
239	    };
240	}
241	
242	/**
243	 * Calculate composite score for a swap based on matches
244	 * @param {Match3Game} game - The game instance
245	 * @param {Array} matches - Array of match objects
246	 * @returns {number}
247	 */
248	export function calculateSwapScore(game, matches) {
249	    let score = 0;
250	
251	    let maxFormationScore = 0;
252	    let totalTilesCleared = 0;
253	    let maxValue = 0;
254	    let goalProgress = 0;
255	    let blockedCleared = 0;
256	    let hasSpecialTile = false;
257	
258	    for (const match of matches) {
259	        // Formation type priority
260	        let formationScore = 0;
261	        const direction = match.direction;
262	
263	        if (direction === "line_5_horizontal" || direction === "line_5_vertical") {
264	            formationScore = 1000;
265	        } else if (direction === "T-formation" || direction === "L-formation") {
266	            formationScore = 800;
267	        } else if (direction === "line_4_horizontal" || direction === "line_4_vertical") {
268	            formationScore = 600;
269	        } else if (direction === "block_4_formation") {
270	            formationScore = 500;
271	        } else {
272	            formationScore = 300; // 3-line matches
273	        }
274	
275	        maxFormationScore = Math.max(maxFormationScore, formationScore);
276	
277	        // Count tiles cleared
278	        totalTilesCleared += match.tiles.length;
279	
280	        // Track max value
281	        maxValue = Math.max(maxValue, match.value);
282	
283	        // Check for special tile creation based on formation type
284	        if (direction === "T-formation" || direction === "L-formation" || direction.includes("line_5")) {
285	            hasSpecialTile = true;
286	        }
287	    }
288	
289	    // Calculate goal progress and detect goal-completing moves.
290	    // Tile values are internal log-scale (e.g. 4 = "16", 5 = "32").
291	    // Merging tiles of value V produces a tile of value V+1 (normal) or V+2 (T/L/5-line).
292	    let goalsCompleted = 0;
293	    if (game.levelGoals && game.levelGoals.length > 0) {
294	        for (const goal of game.levelGoals) {
295	            let progressForGoal = 0;
296	            for (const match of matches) {
297	                const isBigFormation =
298	                    match.direction === "T-formation" ||
299	                    match.direction === "L-formation" ||
300	                    match.direction === "line_5_horizontal" ||
301	                    match.direction === "line_5_vertical";
302	                const producedValue = match.value + (isBigFormation ? 2 : 1);
303	
304	                if (goal.goalType === "created" && producedValue === goal.tileValue) {
305	                    // Each merge group produces one tile of producedValue
306	                    progressForGoal += 1;
307	                } else if (goal.goalType === "current" && producedValue === goal.tileValue) {
308	                    progressForGoal += 1;
309	                }
310	            }
311	            goalProgress += progressForGoal;
312	
313	            if (progressForGoal > 0) {
314	                const currentProgress = goal.goalType === "created" ? goal.created : goal.current;
315	                if (currentProgress + progressForGoal >= goal.target) {
316	                    goalsCompleted += 1;
317	                }
318	            }
319	        }
320	    }
321	
322	    // Calculate blocked tiles that would be cleared
323	    // (Check adjacent tiles to matches for blocked tiles)
324	    const matchPositions = new Set();
325	    for (const match of matches) {
326	        for (const tile of match.tiles) {
327	            matchPositions.add(`${tile.row},${tile.col}`);
328	        }
329	    }
330	
331	    // Check adjacent tiles for blocked tiles
332	    for (const match of matches) {
333	        for (const tile of match.tiles) {
334	            const adjacentPositions = [
335	                [tile.row - 1, tile.col],
336	                [tile.row + 1, tile.col],
337	                [tile.row, tile.col - 1],
338	                [tile.row, tile.col + 1],
339	            ];
340	
341	            for (const [adjRow, adjCol] of adjacentPositions) {
342	                if (adjRow >= 0 && adjRow < game.boardHeight && adjCol >= 0 && adjCol < game.boardWidth) {
343	                    const adjTile = game.board[adjRow]?.[adjCol];
344	                    if (
345	                        adjTile &&
346	                        (isBlocked(adjTile) ||
347	                            isBlockedWithLife(adjTile) ||
348	                            isBlockedMovable(adjTile) ||
349	                            isBlockedWithMergeCount(adjTile))
350	                    ) {
351	                        blockedCleared += 1;
352	                    }
353	                }
354	            }
355	        }
356	    }
357	
358	    // NOTE: If there are blocked tiles on the board, there is always a corresponding
359	    // blocked-tiles goal. So we don't need to check whether that goal is currently "open".
360	
361	    // Calculate position bonus (matches closer to bottom trigger more cascades)
362	    let totalRow = 0;
363	    let tileCount = 0;
364	    for (const match of matches) {
365	        for (const tile of match.tiles) {
366	            totalRow += tile.row;
367	            tileCount++;
368	        }
369	    }
370	    // Average row position (0 = top, boardHeight-1 = bottom)
371	    // Bonus scales from 0 to ~150 based on position
372	    const avgRow = tileCount > 0 ? totalRow / tileCount : 0;
373	    const positionBonus = Math.round((avgRow / (game.boardHeight - 1)) * 150);
374	
375	    // Compute composite score
376	    score += maxFormationScore;
377	    score += totalTilesCleared * 50;
378	    score += goalProgress * 100;
379	    // Moves that complete a goal dominate all other factors except blocked tiles
380	    score += goalsCompleted * 8000;
381	
382	    // Blocked tile scoring
383	    // If a swap clears blocked tiles, heavily prefer it.
384	    if (blockedCleared > 0) {
385	        // Massive bonus that dominates most other factors, scaled by cleared blocked tiles.
386	        score += 10000 + blockedCleared * 500;
387	    }
388	
389	    score += hasSpecialTile ? 200 : 0;
390	    score += maxValue * 5;
391	    score += positionBonus;
392	
393	    return score;
394	}
395	
396	/**
397	 * Get the tiles that would be matched if a swap is performed
398	 * Used by swap preview during drag
399	 * @param {Match3Game} game - The game instance
400	 * @param {number} row1 - First tile row
401	 * @param {number} col1 - First tile column
402	 * @param {number} row2 - Second tile row
403	 * @param {number} col2 - Second tile column
404	 * @returns {Array<{row: number, col: number}>} Array of tile positions in PRE-SWAP coordinates
405	 */
406	export function getMatchTilesForSwap(game, row1, col1, row2, col2) {
407	    // Save original board reference and flags (don't modify the original)
408	    const originalBoard = game.board;
409	    const originalIsUserSwap = game.isUserSwap;
410	    const originalLastSwapPosition = game.lastSwapPosition;
411	
412	    // Create a working copy for the evaluation
413	    game.board = originalBoard.map((row) => row.map((tile) => (tile ? { ...tile } : null)));
414	
415	    // Swap tiles on the working copy
416	    const temp = game.board[row1][col1];
417	    game.board[row1][col1] = game.board[row2][col2];
418	    game.board[row2][col2] = temp;
419	
420	    // Set flag for joker activation
421	    game.isUserSwap = true;
422	    game.lastSwapPosition = {
423	        row: row2,
424	        col: col2,
425	        movedFrom: { row: row1, col: col1 },
426	    };
427	
428	    // Check if this swap creates matches
429	    const hasMatches = hasMatchesForSwap(game, row1, col1, row2, col2);
430	
431	    let matchTiles = [];
432	    if (hasMatches) {
433	        // Get detailed match information
434	        const matches = findMatches(game);
435	
436	        // Only include matches that involve the actively dragged tile
437	        // The dragged tile starts at (row1, col1) and after swap is at (row2, col2)
438	        const relevantMatches = matches.filter((match) =>
439	            match.tiles.some((tile) => tile.row === row2 && tile.col === col2),
440	        );
441	
442	        // Collect tiles from relevant matches only
443	        // Translate post-swap positions back to pre-swap positions for display
444	        for (const match of relevantMatches) {
445	            for (const tile of match.tiles) {
446	                let displayRow = tile.row;
447	                let displayCol = tile.col;
448	
449	                // If this tile is at a swap position, translate it back
450	                if (tile.row === row1 && tile.col === col1) {
451	                    // This tile is at position 1 after swap, so it was at position 2 before
452	                    displayRow = row2;
453	                    displayCol = col2;
454	                } else if (tile.row === row2 && tile.col === col2) {
455	                    // This tile is at position 2 after swap, so it was at position 1 before
456	                    displayRow = row1;
457	                    displayCol = col1;
458	                }
459	
460	                matchTiles.push({ row: displayRow, col: displayCol });
461	            }
462	        }
463	    }
464	
465	    // Restore original board reference (not a copy)
466	    game.board = originalBoard;
467	    game.isUserSwap = originalIsUserSwap;
468	    game.lastSwapPosition = originalLastSwapPosition;
469	
470	    return matchTiles;
471	}
