        showHomeScreen(game);
    } else {
        alert("Congratulations! You've completed all levels! 🏆");
    }
}

export function restartLevel(game) {
    game.hideLevelSolved();
    game.hideLevelFailed();
    game.loadLevel(game.currentLevel);
    game.createBoard();
    game.renderBoard();
    game.showGoalDialogIfNeeded();

