.hint-nudge-up {
    animation: hintNudgeUp 0.8s ease-in-out infinite alternate;
}

.hint-nudge-down {
    animation: hintNudgeDown 0.8s ease-in-out infinite alternate;
}

.hint-nudge-left {
    animation: hintNudgeLeft 0.8s ease-in-out infinite alternate;
}

.hint-nudge-right {
    animation: hintNudgeRight 0.8s ease-in-out infinite alternate;
}

@keyframes hintNudgeUp {
    0%,
    50% {
        transform: translateY(0);
    }
    25% {
        transform: translateY(-15%);
    }
}

@keyframes hintNudgeDown {
    0%,
    50% {
        transform: translateY(0);
    }
    25% {
        transform: translateY(15%);
    }
}

@keyframes hintNudgeLeft {
    0%,
    50% {
        transform: translateX(0);
    }
    25% {
        transform: translateX(-15%);
    }
}

@keyframes hintNudgeRight {
    0%,
    50% {
        transform: translateX(0);
    }
    25% {
        transform: translateX(15%);
    }
}

